  "title": "`IN` ऑपरेटर का उपयोग",
  "group": "SQL ऑपरेटर्स",
  "options": [
    {
      "text": "अद्वितीय पंक्तियाँ लौटाता है"
    },
    {
      "text": "इंडेक्स वाले कॉलम की आवश्यकता होती है"
    },
    {
      "text": "केवल संख्यात्मक कॉलम पर लागू होता है"
    },
    {
      "text": "निर्दिष्ट सूची में मौजूद मानों से मेल खाने वाली पंक्तियाँ लौटाता है"
    }
  ],
  "questionProse": [
    "SQL में `IN` ऑपरेटर का असली काम क्या है?"
  ],
  "explanationProse": [
    "`IN` ऑपरेटर पंक्तियों को फ़िल्टर करता है ताकि वे किसी निर्दिष्ट सूची में मौजूद किसी भी मान से मेल खा सकें। यह अक्सर कई `OR` कंडीशन्स का विकल्प होता है।\n\nहालाँकि यह *अद्वितीय पंक्तियाँ* लौटा *सकता है* (और अक्सर लौटाता भी है), लेकिन यह इसका मुख्य उद्देश्य नहीं है।\n\nयहाँ इंडेक्सिंग अनिवार्य नहीं है, हालाँकि `IN` का उपयोग इंडेक्स वाले कॉलम पर करना एक बेहतर प्रैक्टिस है, खासकर अगर वह `UNIQUE` इंडेक्स हो, क्योंकि इससे परफॉर्मेंस में सुधार होता है।"
  ]
}
